const items = $input.all();
return items.map(item => {
  const d = item.json;
  const body = d.body || d;
  const storeId = body.store_id || body._store_id || '';
  const phone = (body.phone || '').replace(/[^0-9+]/g, '');
  const orderId = body.order_id || '';
  const msgText = (body.message_text || body.text || '').trim();
  const msgType = body.message_type || 'text';
  const lang = body.language || 'dz';
  const missing = [];
  if (!storeId) missing.push('store_id');
  if (!phone) missing.push('phone');
  if (!msgText) missing.push('message_text');
  return {
    json: {
      ...d,
      _store_id: storeId,
      _phone: phone,
      _order_id: orderId,
      _message_text: msgText.substring(0, 4096),
      _message_type: msgType,
      _language: lang,
      _valid: missing.length === 0,
      _missing: missing,
      _idempotency_key: storeId + '_' + phone + '_' + Date.now()
    }
  };
});

const items = $input.all();
return items.map(item => {
  const j = item.json;
  const store = j._store || j;
  const order = j._order || j;
  const settings = j._ai_settings || j;
  const history = Array.isArray(j) ? j : (j._history || []);

  const msgCount = history.length;
  const lang = settings.language || j._language || 'dz';
  const maxMsgs = settings.max_messages || 20;
  const needsHumanEscalation = msgCount >= 8;

  const languageInstruction = lang === 'dz'
    ? 'Speak Algerian Arabic (Darija). Use words like "صح", "واش", "هادا", "برك", "دوك".'
    : lang === 'ar'
      ? 'Speak Arabic (العربية).'
      : 'Speak French. Respond in French.';

  const orderInfo = order.id
    ? `Order #${order.id.substring(0,8)} | Product: ${order.product || 'N/A'} | Amount: ${order.amount || 'N/A'} DA | Customer: ${order.customer_name || 'N/A'} | Status: ${order.status || 'pending'} | Phone: ${order.phone || 'N/A'} | Wilaya: ${order.wilaya || 'N/A'} | Commune: ${order.commune || 'N/A'}`
    : 'No order information available.';

  const merchantPrompt = settings.system_prompt || '';
  const fallbackMsg = settings.fallback_message || 'Désolé, je n\'ai pas compris. Pouvez-vous reformuler ?';
  const handoffMsg = settings.handoff_message || 'Un agent va vous contacter sous peu. Merci pour votre patience.';

  const historyText = history.map(h => `${h.role}: ${h.message}`).join('\n');

  const systemContent = [
    merchantPrompt ? `=== MERCHANT INSTRUCTIONS ===\n${merchantPrompt}\n=== END MERCHANT INSTRUCTIONS ===` : '',
    `You are an AI Order Confirmation Agent. You work for "${store.store_name || store.name || 'the store'}".`,
    `Your ONLY job is to confirm or process customer orders via WhatsApp. You are NOT a salesman.`,
    `You NEVER invent order information. ONLY use the database values provided below.`,
    `You NEVER modify data without explicit customer confirmation.`,
    `Be polite, professional, and helpful.`,
    `${languageInstruction}`,
    `Understand and respond to messages in Darija, Arabic, French, or English as appropriate.`,
    `\n=== CURRENT ORDER ===\n${orderInfo}`,
    historyText ? `\n=== CONVERSATION HISTORY (last ${history.length} messages) ===\n${historyText}` : '',
    `\n=== RESPONSE RULES ===`,
    `You MUST respond ONLY with valid JSON. Never include any text outside the JSON.`,
    `Supported intents: confirm, cancel, change_address, change_phone, change_wilaya, change_commune, question, human`,
    `- confirm: Customer explicitly confirms the order (e.g. "oui je confirme", "صح", "ok" )`,
    `- cancel: Customer explicitly cancels (e.g. "annuler", "non merci", "لاغي" )`,
    `- change_address: Customer wants to change delivery address entirely`,
    `- change_phone: Customer provides a new phone number`,
    `- change_wilaya: Customer changes wilaya (province/state)`,
    `- change_commune: Customer changes commune (city/district)`,
    `- question: Customer asks a question about the order, delivery, payment`,
    `- human: Customer is angry, asks for manager, or requests human support`,
    ``,
    `IMPORTANT ESCALATION RULES:`,
    `- If customer is angry, aggressive, or explicitly asks for a manager → use intent "human"`,
    `- If you are unsure or cannot understand → use intent "question" and ask for clarification`,
    `- Never confirm unless the customer EXPLICITLY confirms`,
    `- If confidence in intent is below 0.65, set lower confidence value`,
    ``,
    `RESPONSE FORMAT:`,
    `{"intent": "string (one of the 8 intents)", "reply": "string (your response to the customer in the correct language)", "confidence": 0.0-1.0}`
  ].filter(Boolean).join('\n\n');

  const messages = [
    { role: 'system', content: systemContent },
    ...history.map(h => ({ role: h.role === 'customer' ? 'user' : 'assistant', content: h.message })),
    { role: 'user', content: `Customer message: ${j._message_text || 'The customer is responding to the order confirmation.'}` }
  ];

  return {
    json: {
      ...j,
      _store: store,
      _order: order,
      _ai_settings: settings,
      _history: history,
      _openai_messages: messages,
      _model: settings.model || 'gpt-4o-mini',
      _temperature: Number(settings.temperature) || 0.7,
      _msg_count: msgCount,
      _needs_escalation: needsHumanEscalation,
      _fallback_message: fallbackMsg,
      _handoff_message: handoffMsg,
      _language: lang
    }
  };
});

const items = $input.all();
const startTime = Date.now();
return items.map(item => {
  const j = item.json;
  const choice = j.choices?.[0]?.message;
  if (!choice) {
    return { json: { ...j, _parse_error: true, _ai_intent: 'human', _ai_reply: j._fallback_message || 'Désolé, une erreur est survenue.', _ai_confidence: 0, _tokens_used: 0, _latency_ms: 0, _model_used: 'error' } };
  }
  const content = choice.content || '';
  const tokensUsed = j.usage?.total_tokens || 0;
  const latencyMs = Date.now() - startTime;
  const modelUsed = j.model || 'gpt-4o-mini';
  try {
    const parsed = JSON.parse(content);
    return {
      json: {
        ...j,
        _ai_intent: (parsed.intent || 'question').toLowerCase(),
        _ai_reply: parsed.reply || 'Merci pour votre message.',
        _ai_confidence: Math.min(1, Math.max(0, Number(parsed.confidence) || 0.5)),
        _ai_raw: parsed,
        _tokens_used: tokensUsed,
        _latency_ms: latencyMs,
        _model_used: modelUsed,
        _parse_error: false
      }
    };
  } catch (e) {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        const parsed = JSON.parse(jsonMatch[0]);
        return {
          json: {
            ...j,
            _ai_intent: (parsed.intent || 'question').toLowerCase(),
            _ai_reply: parsed.reply || content.substring(0, 500),
            _ai_confidence: Math.min(1, Math.max(0, Number(parsed.confidence) || 0.3)),
            _ai_raw: parsed,
            _tokens_used: tokensUsed,
            _latency_ms: latencyMs,
            _model_used: modelUsed,
            _parse_error: true
          }
        };
      } catch (e2) {}
    }
    return {
      json: {
        ...j,
        _ai_intent: 'question',
        _ai_reply: content.substring(0, 500) || 'Merci pour votre message.',
        _ai_confidence: 0.3,
        _ai_raw: { intent: 'question', reply: content.substring(0, 500) },
        _tokens_used: tokensUsed,
        _latency_ms: latencyMs,
        _model_used: modelUsed,
        _parse_error: true
      }
    };
  }
});

const items = $input.all();
return items.map(item => {
  const j = item.json;
  return {
    json: {
      ...j,
      _ai_intent: 'human',
      _ai_reply: j._handoff_message || 'Un agent va vous contacter sous peu. Merci pour votre patience.',
      _ai_confidence: 0,
