const items = $input.all();
return items.map(async item => {
  const j = item.json;
  const supabaseUrl = $env.SUPABASE_URL;
  const serviceKey = $env.SUPABASE_SERVICE_KEY;
  const headers = { 'apikey': serviceKey, 'Authorization': 'Bearer ' + serviceKey, 'Content-Type': 'application/json' };
  const orderId = j._order?.id || j._order_id || '';
  const storeId = j._store?.id || j.id || j._store_id;
  try {
    await fetch(supabaseUrl + '/rest/v1/orders?id=eq.' + encodeURIComponent(orderId), {
      method: 'PATCH', headers,
      body: JSON.stringify({ status: 'confirmed', notes: 'Confirmed via AI Agent' })
    });
    await fetch(supabaseUrl + '/rest/v1/rpc/insert_order_activity', {
      method: 'POST', headers,
      body: JSON.stringify({ p_order_id: orderId, p_activity_type: 'confirmed', p_description: 'Order confirmed by customer via AI Agent' })
    });
  } catch (e) {}
  return { json: { ...j, _order_update: { status: 'confirmed' } } };
});

