const items = $input.all();
return items.map(async item => {
  const j = item.json;
  const supabaseUrl = $env.SUPABASE_URL;
  const serviceKey = $env.SUPABASE_SERVICE_KEY;
  const headers = { 'apikey': serviceKey, 'Authorization': 'Bearer ' + serviceKey, 'Content-Type': 'application/json' };
  const orderId = j._order?.id || j._order_id || '';
  const reply = j._ai_reply || '';
  const addressMatch = reply.match(/address[\s\S]*?wilaya[\s:]*(\w+)/i);
  const communeMatch = reply.match(/commune[\s:]*(\w+)/i);
  const updateData = {};
  if (addressMatch) updateData.wilaya = addressMatch[1];
  if (communeMatch) updateData.commune = communeMatch[1];
  updateData.notes = 'Address updated via AI Agent';
  try {
    await fetch(supabaseUrl + '/rest/v1/orders?id=eq.' + encodeURIComponent(orderId), {
      method: 'PATCH', headers,
      body: JSON.stringify(updateData)
    });
  } catch (e) {}
  return { json: { ...j, _order_update: updateData } };
});

