={{ (() => {
  const j = $json;
  let type = 'ai_reply';
  let title = 'AI Agent Reply';
  if (j._ai_intent === 'confirm') { type = 'order_confirmed'; title = 'Order Confirmed'; }
  else if (j._ai_intent === 'cancel') { type = 'order_cancelled'; title = 'Order Cancelled'; }
  else if (j._ai_intent === 'human') { type = 'ai_escalated'; title = 'AI Escalation'; }
  else if (['change_address','change_phone','change_wilaya','change_commune'].includes(j._ai_intent)) { type = 'order_modified'; title = 'Order Modified'; }
  return {
    p_store_id: j._store?.id || j.id || j._store_id,
    p_type: type,
    p_title: title,
    p_message: (j._ai_reply || '').substring(0, 500),
    p_data: { order_id: j._order?.id || j._order_id, phone: j._phone, intent: j._ai_intent, confidence: j._ai_confidence }
  };
})() }}

