const items = $input.all();
return items.map(item => {
  const j = item.json;
  const store = j._store || j;
  const phoneNumberId = store.phone_number_id;
  const accessToken = store.access_token;
  const replyText = j._ai_reply || 'Merci pour votre message.';
  const truncated = replyText.length > 4000 ? replyText.substring(0, 4000) : replyText;
  return {
    json: {
      ...j,
      _whatsapp_payload: {
        url: 'https://graph.facebook.com/v18.0/' + phoneNumberId + '/messages',
        headers: {
          'Authorization': 'Bearer ' + accessToken,
          'Content-Type': 'application/json'
        },
        body: {
          messaging_product: 'whatsapp',
          recipient_type: 'individual',
          to: j._phone,
          type: 'text',
          text: { body: truncated }
        }
      }
    }
  };
});

const items = $input.all();
return items.map(item => {
  const d = item.json;
  const errMsg = d.errorMessage || d.error || d._error || 'Unknown workflow error';
  const errCode = d.errorCode || d.statusCode || '500';
  return {
    json: {
      _dlq_store_id: d._store_id || d.store_id || d.id || null,
      _dlq_error_message: String(errMsg).substring(0, 1000),
      _dlq_error_code: String(errCode),
      _dlq_input_data: {
        store_id: d._store_id || d.store_id,
        phone: d._phone || d.phone,
        order_id: d._order_id || d.order_id,
        message_text: (d._message_text || '').substring(0, 200)
      }
    }
  };
});
